import json, sys
data = json.load(sys.stdin)
models = data.get('data', [])
free_models = []
cheap_models = []
for m in models:
    p = m.get('pricing', {})
    if isinstance(p.get('prompt'), list):
        price_in = p['prompt'][0]['price']
    else:
        price_in = p.get('prompt', 999)
    if isinstance(p.get('completion'), list):
        price_out = p['completion'][0]['price']
    else:
        price_out = p.get('completion', 999)
    if price_in == 0 and price_out == 0:
        free_models.append(m['id'])
    elif price_in <= 0.15:
        cheap_models.append((m['id'], price_in, price_out))

print('=== FREE (Rp 0) ===')
if free_models:
    for f in free_models:
        print(f'  ✅ {f}')
else:
    print('  ❌ Gak ada model gratis')

print(f'\n=== PALING MURAH (≤ \$0.15/1M in) ===')
for mid, pi, po in sorted(cheap_models, key=lambda x: x[1]):
    print(f'  💰 {mid:30s} | in: \${pi} | out: \${po}')
""}
